#!/bin/bash
set -e
cd "$(dirname "$0")"
python3 -c "import base64; open('scripts/daily-agent.sh', 'wb').write(base64.b64decode(''))"
chmod +x scripts/daily-agent.sh
echo "✅ daily-agent.sh 更新"
git add scripts/daily-agent.sh
git commit -m "fix: cron - set HOME/GIT_CONFIG for git push, use absolute path for .env.local"
git push origin main
echo "🚀 Push完了！"
echo ""
echo "=== 今日の変更分もpush済みか確認 ==="
git log --oneline -5
